const webhook = $('Webhook').first().json;
const body = webhook.body || webhook;

return [{
  json: {
    tracking_id: body.tracking_id || ""
  },
  binary: $input.item.binary
}];

// 필수 컬럼 목록 (여러 변형 포함)
const requiredColumnsVariants = {
  'DBMS명': ['DBMS명', 'DBMS 명', 'dbms명', 'dbms 명'],
  '스키마명': ['스키마명', '스키마 명', 'schema명', 'schema 명'],
  '영문테이블명': ['영문테이블명', '영문 테이블명', '영문테이블명*', '영문 테이블명*', '테이블명', '테이블 명'],
  '한글컬럼명': ['한글컬럼명', '한글 컬럼명', '한글컬럼명*', '한글 컬럼명*', '컬럼명', '컬럼 명'],
  '영문컬럼명': ['영문컬럼명', '영문 컬럼명', '영문컬럼명*', '영문 컬럼명*'],
  '데이터타입': ['데이터타입', '데이터 타입', '데이터타입*', '데이터 타입*', 'data type', 'datatype']
};

// 입력 데이터 가져오기
const items = $input.all();

console.log('=== 입력 데이터 확인 ===');
console.log('총 아이템 수:', items.length);

if (items.length > 0) {
  console.log('첫 번째 아이템의 컬럼명:', Object.keys(items[0].json));
}

// 실제 컬럼명 매핑 함수
function findActualColumnName(itemKeys, targetColumn) {
  const variants = requiredColumnsVariants[targetColumn];

  for (const variant of variants) {
    // 정확히 일치하는 경우
    if (itemKeys.includes(variant)) {
      return variant;
    }

    // 대소문자 무시하고 일치하는 경우
    const found = itemKeys.find(key => 
      key.toLowerCase().replace(/\s+/g, '') === variant.toLowerCase().replace(/\s+/g, '')
    );
    if (found) {
      return found;
    }
  }

  return null;
}

// 첫 번째 아이템에서 실제 컬럼명 매핑 찾기
const columnMapping = {};
if (items.length > 0) {
  const itemKeys = Object.keys(items[0].json);

  for (const [standardName, variants] of Object.entries(requiredColumnsVariants)) {
    const actualName = findActualColumnName(itemKeys, standardName);
    if (actualName) {
      columnMapping[standardName] = actualName;
      console.log(`매핑 발견: ${standardName} -> ${actualName}`);
    }
  }
}

// 필수 컬럼 확인
const requiredColumns = Object.keys(requiredColumnsVariants);
const missingMappings = requiredColumns.filter(col => !columnMapping[col]);

if (missingMappings.length > 0) {
  console.error('매핑을 찾을 수 없는 필수 컬럼:', missingMappings);
  throw new Error(`필수 컬럼 매핑을 찾을 수 없습니다: ${missingMappings.join(', ')}. 실제 컬럼명을 확인해주세요.`);
}

// 컬럼 정보 수집
const columnData = [];

for (const item of items) {
  // 필수 컬럼 검증 (매핑된 이름 사용)
  const missingColumns = requiredColumns.filter(col => {
    const actualCol = columnMapping[col];
    return !item.json[actualCol] || item.json[actualCol].toString().trim() === '';
  });

  if (missingColumns.length > 0) {
    console.log(`행 건너뜀 - 필수컬럼 누락: ${missingColumns.join(', ')}`);
    continue;
  }

  columnData.push({
    DBMS명: item.json[columnMapping['DBMS명']],
    스키마명: item.json[columnMapping['스키마명']],
    영문테이블명: item.json[columnMapping['영문테이블명']],
    한글컬럼명: item.json[columnMapping['한글컬럼명']],
    영문컬럼명: item.json[columnMapping['영문컬럼명']],
    데이터타입: item.json[columnMapping['데이터타입']],
    컬럼설명: item.json['컬럼설명'] || item.json['컬럼 설명'] || '',
    NotNull여부: item.json['Not Null 여부'] || item.json['NotNull여부'] || item.json['NotNull 여부'] || '',
    PK정보: item.json['PK정보(Primary key)'] || item.json['PK정보'] || item.json['PK 정보'] || '',
    FK정보: item.json['FK정보(Foreign Key)'] || item.json['FK정보'] || item.json['FK 정보'] || ''
  });
}

console.log('=== 수집된 컬럼 데이터 ===');
console.log('유효한 컬럼 수:', columnData.length);

if (columnData.length === 0) {
  throw new Error('유효한 컬럼 데이터가 없습니다. 필수 컬럼을 확인해주세요.');
}

// 테이블별로 그룹화
const tableGroups = {};

for (const col of columnData) {
  const tableKey = `${col.DBMS명}_${col.스키마명}_${col.영문테이블명}`;

  if (!tableGroups[tableKey]) {
    tableGroups[tableKey] = {
      DBMS명: col.DBMS명,
      스키마명: col.스키마명,
      영문테이블명: col.영문테이블명,
      columns: []
    };
  }

  tableGroups[tableKey].columns.push({
    한글컬럼명: col.한글컬럼명,
    영문컬럼명: col.영문컬럼명,
    데이터타입: col.데이터타입,
    컬럼설명: col.컬럼설명,
    NotNull여부: col.NotNull여부,
    PK정보: col.PK정보,
    FK정보: col.FK정보
  });
}

// 모든 컬럼 정보를 하나의 아이템으로 통합
const allTables = Object.values(tableGroups);

console.log('=== 테이블 그룹화 결과 ===');
console.log('총 테이블 수:', allTables.length);
allTables.forEach((table, idx) => {
  console.log(`테이블 ${idx + 1}: ${table.DBMS명}.${table.스키마명}.${table.영문테이블명} (컬럼 ${table.columns.length}개)`);
});

// AI Agent용 프롬프트 생성
const prompt = `다음 테이블들의 컬럼 정보를 분석하여 각 테이블별로 업무규칙을 생성해주세요.

${allTables.map((table, idx) => `
## 테이블 ${idx + 1}
- DBMS명: ${table.DBMS명}
- 스키마명: ${table.스키마명}
- 테이블명: ${table.영문테이블명}

### 컬럼 정보
${JSON.stringify(table.columns, null, 2)}
`).join('\n')}

## 요청사항
위 모든 테이블에 대해 각각 최소 3개 이상의 업무규칙을 생성해주세요.
각 규칙은 다음 형식의 JSON 배열로 응답해주세요:

[
  {
    "DBMS명": "테이블의 DBMS명",
    "스키마명": "테이블의 스키마명",
    "테이블명": "테이블의 영문테이블명",
    "업무규칙명": "규칙 이름",
    "품질지표명": "논리관계 일관성|시간순서 일관성|계산식",
    "설명": "규칙에 대한 설명",
    "건수SQL": "SELECT COUNT(*) FROM 스키마명.테이블명",
    "분석SQL": "오류를 검출하는 SQL문"
  }
]

**중요**: 반드시 유효한 JSON 배열만 응답하고, 다른 설명이나 마크다운은 포함하지 마세요.`;

return [{
  json: {
    chatInput: prompt,
    allTableData: allTables,
    totalTables: allTables.length,
    totalColumns: columnData.length
  }
}];

// AI Agent 응답 가져오기
const items = $input.all();
const agentResponse = items[0].json.output;
const tableData = items[0].json.allTableData;

console.log('=== AI Agent 응답 파싱 ===');
console.log('원본 응답 길이:', agentResponse.length);

// JSON 파싱 (마크다운 코드블록 제거)
let rules;
try {
  // ```json 과 ``` 제거
  const cleanResponse = agentResponse
    .replace(/```json\s*/g, '')
    .replace(/```\s*/g, '')
    .trim();

  console.log('정제된 응답:', cleanResponse.substring(0, 200) + '...');

  rules = JSON.parse(cleanResponse);
  console.log('파싱 성공: 규칙 개수 =', rules.length);
} catch (error) {
  console.error('JSON 파싱 오류:', error.message);
  console.log('원본 응답:', agentResponse);
  throw new Error('AI 응답을 JSON으로 파싱할 수 없습니다: ' + error.message);
}

if (!Array.isArray(rules)) {
  console.error('규칙이 배열 형식이 아닙니다:', typeof rules);
  throw new Error('AI 응답이 배열 형식이 아닙니다.');
}

// 필수 필드 검증 (컬럼명 추가)
const requiredFields = ['업무규칙명', '컬럼명', '품질지표명', '설명', '건수SQL', '분석SQL'];
const validRules = [];
const invalidRules = [];

rules.forEach((rule, index) => {
  const missingFields = requiredFields.filter(field => !rule[field]);

  if (missingFields.length > 0) {
    console.log(`규칙 ${index + 1} 건너뜀 - 필수 필드 누락: ${missingFields.join(', ')}`);
    invalidRules.push({ index: index + 1, reason: `필수 필드 누락: ${missingFields.join(', ')}`, rule });
  } else {
    validRules.push(rule);
  }
});

console.log(`총 ${rules.length}개 규칙 중 ${validRules.length}개 유효, ${invalidRules.length}개 무효`);

if (validRules.length === 0) {
  throw new Error('유효한 업무규칙이 없습니다.');
}

// 각 규칙을 개별 아이템으로 변환하고 원본 테이블 데이터 포함
const output = validRules.map((rule, index) => ({
  json: {
    규칙번호: index + 1,
    업무규칙명: rule.업무규칙명,
    DBMS명: rule.DBMS명 || '',
    스키마명: rule.스키마명 || '',
    테이블명: rule.테이블명 || rule.영문테이블명 || '',
    컬럼명: rule.컬럼명 || '',
    품질지표명: rule.품질지표명,
    설명: rule.설명,
    건수SQL: rule.건수SQL,
    분석SQL: rule.분석SQL,
    원본테이블데이터: tableData
  }
}));

return output;

// 5. 검토 프롬프트 생성 - 여러 규칙(여러 아이템) 모두 처리

const items = $input.all();

if (!items || items.length === 0) {
  throw new Error('입력된 업무규칙 아이템이 없습니다.');
}

function asText(v) {
  if (v === null || v === undefined) return '';
  if (typeof v === 'string') return v;
  try { return JSON.stringify(v); } catch (e) { return String(v); }
}

const output = items.map((item, idx) => {
  const rule = item.json || {};
  const tableData = rule.원본테이블데이터 || [];

  // 원본 테이블 데이터에서 해당 테이블 찾기
  const targetTable = tableData.find(t =>
    asText(t.DBMS명) === asText(rule.DBMS명) &&
    asText(t.스키마명) === asText(rule.스키마명) &&
    asText(t.영문테이블명) === asText(rule.테이블명)
  );

  const columnInfo = targetTable ? JSON.stringify(targetTable.columns, null, 2) : '정보 없음';

  // 규칙별 검토 프롬프트 생성
  const prompt = `다음 업무규칙의 정확성을 검토하고 결과를 JSON 형식으로 응답해주세요.

## 테이블 정보
- DBMS명: ${asText(rule.DBMS명)}
- 스키마명: ${asText(rule.스키마명)}
- 테이블명: ${asText(rule.테이블명)}

## 컬럼 정보
${columnInfo}

## 생성된 업무규칙
- 업무규칙명: ${asText(rule.업무규칙명)}
- 품질지표명: ${asText(rule.품질지표명)}
- 설명: ${asText(rule.설명)}
- 건수SQL: ${asText(rule.건수SQL)}
- 분석SQL: ${asText(rule.분석SQL)}

## 검토 요청
위 업무규칙을 품질지표명(${asText(rule.품질지표명)})에 해당하는 검토 기준으로 평가하세요.

다음 JSON 형식으로만 응답하세요:

{
  "검토결과": "적합|부적합",
  "검토의견": "검토 기준별 평가 내용 (적합한 경우 간단히, 부적합한 경우 상세히)",
  "문제점": "부적합한 경우 구체적인 문제점 (적합한 경우 빈 문자열)",
  "수정제안": "부적합한 경우 수정 방안 (적합한 경우 빈 문자열)"
}

**중요**: 반드시 유효한 JSON만 응답하고, 다른 설명은 포함하지 마세요.`;

  return {
    json: {
      chatInput: prompt,
      originalRule: rule,       // 규칙 원본을 그대로 다음 노드로 전달
      _ruleIndex: idx + 1        // 디버깅용 (선택)
    }
  };
});

return output;

// 7. 검토 결과 파싱 (Robust JSON Parser)
// - Handles: ```json fences, extra text, stray quotes, multiple blocks, etc.
// - Extracts the FIRST valid JSON object and parses it
// - Never throws: returns parse_ok=false with raw_output + parse_error

const items = $input.all();

function stripCodeFences(s) {
  if (s == null) return '';
  let t = String(s).trim();

  // Remove leading/trailing quotes wrapping the whole content (e.g. "```json ...```")
  if (
    (t.startsWith('"') && t.endsWith('"')) ||
    (t.startsWith("'") && t.endsWith("'"))
  ) {
    t = t.slice(1, -1).trim();
  }

  // Remove ```json ... ``` fences
  // Allow variations: ```json, ```JSON, ``` etc
  t = t.replace(/^\s*```(?:json|JSON)?\s*/m, '');
  t = t.replace(/\s*```\s*$/m, '');

  // Also remove any remaining standalone fences (sometimes model repeats)
  t = t.replace(/```(?:json|JSON)?/g, '').replace(/```/g, '');

  return t.trim();
}

// Extract first balanced JSON object from text, respecting strings/escapes
function extractFirstJsonObject(text) {
  const s = stripCodeFences(text);

  const start = s.indexOf('{');
  if (start === -1) return null;

  let depth = 0;
  let inStr = false;
  let strQuote = '';
  let escape = false;

  for (let i = start; i < s.length; i++) {
    const ch = s[i];

    if (inStr) {
      if (escape) {
        escape = false;
      } else if (ch === '\\') {
        escape = true;
      } else if (ch === strQuote) {
        inStr = false;
        strQuote = '';
      }
      continue;
    }

    // not in string
    if (ch === '"' || ch === "'") {
      inStr = true;
      strQuote = ch;
      continue;
    }

    if (ch === '{') depth++;
    if (ch === '}') depth--;

    if (depth === 0) {
      // candidate substring
      const candidate = s.slice(start, i + 1).trim();
      return candidate.length ? candidate : null;
    }
  }
  return null;
}

function tryParseJson(text) {
  const objText = extractFirstJsonObject(text);
  if (!objText) {
    return { ok: false, error: 'No JSON object found', jsonText: null, parsed: null };
  }

  // 1st attempt: direct parse
  try {
    return { ok: true, error: null, jsonText: objText, parsed: JSON.parse(objText) };
  } catch (e1) {
    // 2nd attempt: light repairs
    let repaired = objText;

    // Replace smart quotes
    repaired = repaired
      .replace(/[“”]/g, '"')
      .replace(/[‘’]/g, "'");

    // Remove trailing commas before } or ]
    repaired = repaired.replace(/,\s*([}\]])/g, '$1');

    // If the model used single quotes for keys/strings (rare), convert cautiously:
    // Only do this if it looks like JSON-ish but with single quotes.
    // (Avoid over-aggressive replacements.)
    const looksSingleQuoted =
      repaired.includes("':") || repaired.includes("',") || repaired.includes("'{") || repaired.includes("'}");

    if (looksSingleQuoted && !repaired.includes('\\"')) {
      // Convert keys 'key': to "key":
      repaired = repaired.replace(/'([^']+?)'\s*:/g, '"$1":');
      // Convert values: : 'value' to : "value"
      repaired = repaired.replace(/:\s*'([^']*?)'/g, ': "$1"');
    }

    try {
      return { ok: true, error: null, jsonText: repaired, parsed: JSON.parse(repaired) };
    } catch (e2) {
      return {
        ok: false,
        error: `JSON.parse failed: ${e2.message}`,
        jsonText: repaired,
        parsed: null,
      };
    }
  }
}

return items.map((item, idx) => {
  const raw =
    item?.json?.output ??
    item?.json?.text ??
    item?.json?.response ??
    item?.json?.data ??
    '';

  const result = tryParseJson(raw);

  // Keep workflow alive: always return something
  const out = {
    ...item.json,
    parse_ok: result.ok,
    parse_error: result.ok ? null : `index ${idx}: ${result.error}`,
    raw_output: result.ok ? null : String(raw),
  };

  if (result.ok && result.parsed && typeof result.parsed === 'object') {
    // Flatten parsed fields at top-level (so 다음 노드에서 바로 쓰기 쉬움)
    // + 원본도 같이 보관
    out.review = result.parsed;

    // If parsed schema is exactly the 10 keys, copy them up too
    // (safe even if extra keys exist)
    for (const [k, v] of Object.entries(result.parsed)) {
      // prevent overwriting existing critical fields unless you want it
      out[k] = v;
    }
  }

  return { json: out };
});

// Form Trigger에서 온 데이터 확인
const items = $input.all();

if (items.length === 0) {
  throw new Error('입력 데이터가 없습니다.');
}

const item = items[0];

console.log('=== Form Trigger 출력 데이터 구조 ===');
console.log('JSON keys:', Object.keys(item.json));
console.log('Binary keys:', Object.keys(item.binary || {}));

// Binary 데이터가 있는지 확인
if (!item.binary || Object.keys(item.binary).length === 0) {
  throw new Error('업로드된 파일이 없습니다. Form에서 파일을 업로드해주세요.');
}

// 첫 번째 binary 필드 이름 가져오기
const binaryFieldName = Object.keys(item.binary)[0];
console.log('Binary field name:', binaryFieldName);

// Binary 데이터를 그대로 전달하되, 표준 이름으로 변경
return [{
  json: item.json,
  binary: {
    'data': item.binary[binaryFieldName]
  }
}];

