// 11. 수정된 규칙 파싱 (Output JSON Parser + Robust Mapper)
// - 10번 AI Agent 출력이 item.json.output (```json ... ```) 문자열로 올 때 JSON 추출/파싱
// - 이미 object로 올 때도 지원
// - originalRule(원문) 보존 흐름도 그대로 지원
// - 어떤 경우에도 죽지 않게 방어 + 디버깅용 raw_output/parse_error 제공

const items = $input.all();

function asText(v) {
  if (v === null || v === undefined) return '';
  if (typeof v === 'string') return v;
  try { return JSON.stringify(v); } catch (e) { return String(v); }
}

function stripCodeFences(s) {
  if (s === null || s === undefined) return '';
  let t = String(s).trim();

  // ```json / ``` 제거
  t = t.replace(/```(?:json|JSON)?/g, '').replace(/```/g, '').trim();

  // 전체를 감싸는 따옴표 제거
  if (
    (t.startsWith('"') && t.endsWith('"')) ||
    (t.startsWith("'") && t.endsWith("'"))
  ) t = t.slice(1, -1).trim();

  return t.trim();
}

// 문자열에서 첫 JSON(객체/배열) 덩어리 추출
function extractFirstJson(text) {
  const s = stripCodeFences(text);
  const objStart = s.indexOf('{');
  const arrStart = s.indexOf('[');
  if (objStart === -1 && arrStart === -1) return null;

  let start, openCh, closeCh;
  if (objStart !== -1 && (arrStart === -1 || objStart < arrStart)) {
    start = objStart; openCh = '{'; closeCh = '}';
  } else {
    start = arrStart; openCh = '['; closeCh = ']';
  }

  let depth = 0;
  let inStr = false;
  let quote = '';
  let esc = false;

  for (let i = start; i < s.length; i++) {
    const ch = s[i];

    if (inStr) {
      if (esc) esc = false;
      else if (ch === '\\') esc = true;
      else if (ch === quote) { inStr = false; quote = ''; }
      continue;
    } else {
      if (ch === '"' || ch === "'") { inStr = true; quote = ch; continue; }
      if (ch === openCh) depth++;
      if (ch === closeCh) depth--;
      if (depth === 0) return s.slice(start, i + 1).trim();
    }
  }
  return null;
}

function tryParseJson(raw) {
  // 이미 object로 들어온 경우
  if (raw && typeof raw === 'object') return { ok: true, parsed: raw, error: null };

  const rawText = asText(raw);
  const jsonText = extractFirstJson(rawText);
  if (!jsonText) return { ok: false, parsed: null, error: 'No JSON found in output' };

  try {
    return { ok: true, parsed: JSON.parse(jsonText), error: null };
  } catch (e1) {
    // 간단 수리(스마트쿼트/트레일링 콤마)
    const repaired = jsonText
      .replace(/[“”]/g, '"')
      .replace(/[‘’]/g, "'")
      .replace(/,\s*([}\]])/g, '$1');

    try {
      return { ok: true, parsed: JSON.parse(repaired), error: null };
    } catch (e2) {
      return { ok: false, parsed: null, error: e2.message };
    }
  }
}

function pick(obj, keys) {
  for (const k of keys) {
    if (obj && obj[k] !== undefined && obj[k] !== null && asText(obj[k]).trim() !== '') {
      return obj[k];
    }
  }
  return '';
}

return items.map((item, idx) => {
  const rule = (item && item.json) ? item.json : {};

  // ✅ 10번 출력은 보통 rule.output에 들어있음
  const rawOutput =
    rule.output ??
    rule.text ??
    rule.response ??
    rule.content ??
    '';

  const parsed = tryParseJson(rawOutput);

  // ✅ src 후보: 1) originalRule 있으면 원문 유지용 / 2) parsed된 결과 / 3) 현재 rule
  const originalRule = (rule.originalRule && typeof rule.originalRule === 'object') ? rule.originalRule : null;

  // 10번 결과(JSON)는 “수정된 규칙”이므로 우선 사용
  const revisedRule = (parsed.ok && parsed.parsed && typeof parsed.parsed === 'object')
    ? parsed.parsed
    : null;

  // 매핑은 revisedRule 우선, 없으면 originalRule, 없으면 rule
  const src = revisedRule || originalRule || rule;

  const ruleNo =
    pick(rule, ['규칙번호', 'ruleNo', '_ruleIndex']) ||
    pick(src,  ['규칙번호', 'ruleNo', '_ruleIndex']) ||
    (idx + 1);

  const 업무규칙명 = pick(src, ['업무규칙명', 'ruleName']);
  const DBMS명     = pick(src, ['DBMS명']);
  const 스키마명   = pick(src, ['스키마명']);
  const 테이블명   = pick(src, ['테이블명', '영문테이블명', 'tableName', '테이블명*']);
  const 컬럼명     = pick(src, ['컬럼명', 'columnName', '컬럼명*']);
  const 품질지표명 = pick(src, ['품질지표명', '품질지표명*']);
  const 설명       = pick(src, ['설명', '설명*']);
  const 건수SQL    = pick(src, ['건수SQL', '건수SQL*']);
  const 분석SQL    = pick(src, ['분석SQL', '분석SQL*']);

  // 디버깅용: 왜 비었는지 바로 보이게
  const missing = [];
  if (asText(업무규칙명).trim() === '') missing.push('업무규칙명');
  if (asText(테이블명).trim() === '') missing.push('테이블명');
  if (asText(컬럼명).trim() === '') missing.push('컬럼명');
  if (asText(품질지표명).trim() === '') missing.push('품질지표명');
  if (asText(설명).trim() === '') missing.push('설명');
  if (asText(건수SQL).trim() === '') missing.push('건수SQL');
  if (asText(분석SQL).trim() === '') missing.push('분석SQL');

  if (missing.length) {
    console.warn(`규칙 ${ruleNo}: 매핑 누락 필드 = ${missing.join(', ')}`);
    if (!parsed.ok) console.warn(`규칙 ${ruleNo}: output parse 실패 = ${parsed.error}`);
  }

  return {
    json: {
      규칙번호: ruleNo,
      업무규칙명: asText(업무규칙명),
      DBMS명: asText(DBMS명),
      스키마명: asText(스키마명),
      '테이블명*': asText(테이블명),
      '컬럼명*': asText(컬럼명),
      '품질지표명*': asText(품질지표명),
      근거규정: '',
      '설명*': asText(설명),
      '건수SQL*': asText(건수SQL),
      '분석SQL*': asText(분석SQL),

      // ✅ 필요하면 나중에 지워도 됨 (원인 추적용)
      _raw_output: asText(rawOutput).slice(0, 5000),
      _parse_ok: !!parsed.ok,
      _parse_error: parsed.ok ? null : parsed.error,
    }
  };
});

// 최종 산출물 형식에 맞게 필드 매핑 및 검증 + 중복 제거
const items = $input.all();

// 중복 제거를 위한 Map (key: 고유 식별자)
const uniqueRules = new Map();

items.forEach((item, idx) => {
  const rule = item.json;

  // 고유 식별자 생성 (DBMS명 + 스키마명 + 테이블명 + 컬럼명 + 품질지표명)
  const uniqueKey = [
    rule.DBMS명 || '',
    rule.스키마명 || '',
    rule.테이블명 || rule['테이블명*'] || '',
    rule.컬럼명 || rule['컬럼명*'] || '',
    rule.품질지표명 || rule['품질지표명*'] || ''
  ].join('||').toLowerCase();

  // 이미 존재하는 경우 건너뛰기
  if (uniqueRules.has(uniqueKey)) {
    console.log(`중복 제거: ${rule.업무규칙명 || 'unnamed'} (${uniqueKey})`);
    return;
  }

  // 필수 필드 검증 (*표시 필드)
  const requiredFields = {
    '테이블명': rule.테이블명 || rule['테이블명*'],
    '컬럼명': rule.컬럼명 || rule['컬럼명*'],
    '품질지표명': rule.품질지표명 || rule['품질지표명*'],
    '설명': rule.설명 || rule['설명*'],
    '건수SQL': rule.건수SQL || rule['건수SQL*'],
    '분석SQL': rule.분석SQL || rule['분석SQL*']
  };

  const missingFields = [];
  for (const [fieldName, value] of Object.entries(requiredFields)) {
    if (!value || value.toString().trim() === '') {
      missingFields.push(fieldName);
    }
  }

  if (missingFields.length > 0) {
    console.warn(`규칙 ${idx + 1} (${rule.업무규칙명 || 'unnamed'}): 필수 필드 누락 - ${missingFields.join(', ')}`);
  }

  // 최종 산출물 형식으로 매핑
  const mappedRule = {
    업무규칙명: rule.업무규칙명 || '',
    DBMS명: rule.DBMS명 || '',
    스키마명: rule.스키마명 || '',
    '테이블명*': rule.테이블명 || rule['테이블명*'] || '',
    '컬럼명*': rule.컬럼명 || rule['컬럼명*'] || '',
    '품질지표명*': rule.품질지표명 || rule['품질지표명*'] || '',
    근거규정: rule.근거규정 || '',
    '설명*': rule.설명 || rule['설명*'] || '',
    '건수SQL*': rule.건수SQL || rule['건수SQL*'] || '',
    '분석SQL*': rule.분석SQL || rule['분석SQL*'] || ''
  };

  // Map에 추가
  uniqueRules.set(uniqueKey, mappedRule);
});

// Map을 배열로 변환
const output = Array.from(uniqueRules.values()).map(rule => ({
  json: rule
}));

console.log(`입력: ${items.length}개 → 중복 제거 후: ${output.length}개 규칙`);
console.log(`총 ${uniqueRules.size}개 고유 규칙을 최종 산출물 형식으로 변환 완료`);

return output;
